+        .simd_digits => dfa.enableDigitsFastPath(),
+        .word_boundary => dfa.enableWordBoundaryFastPath(),
+        .prefix_scan => {
+            if (opt_info.prefix_literal) |lit| {
+                if (std.mem.indexOf(u8, lit, "://") != null) {
