+                } else {
+                    dfa.setPrefixWithWindow(lit, opt_info.window_before, opt_info.window_after);
+                }
+            }
+        },
+        else => {},
+    }
+
+    // Find matches
+    const matches = try dfa.findAll(text, allocator);
+    defer allocator.free(matches);
+
